INSERT INTO public.message_templates (organization_id, name, language, category, components, status, is_preset, sector, purpose) VALUES (NULL, 'dental_first_contact_v1_de', 'de', 'MARKETING', '[{"type":"BODY","text":"Hallo {{1}}, vielen Dank dass Sie unser Formular ausgefuellt haben! Wir haben gesehen dass Sie sich fuer {{2}} interessieren. Unser Spezialistenteam wird sich in Kuerze bei Ihnen melden. Bei Fragen koennen Sie uns gerne hier schreiben."}]', 'draft', true, 'dental', 'first_contact'), (NULL, 'hair_first_contact_v1_de', 'de', 'MARKETING', '[{"type":"BODY","text":"Hallo {{1}}, vielen Dank fuer Ihre Anfrage! Wir haben gesehen dass Sie sich fuer {{2}} interessieren. Unser Expertenteam wird sich in Kuerze bei Ihnen melden. Bei Fragen koennen Sie uns gerne hier schreiben."}]', 'draft', true, 'hair', 'first_contact'), (NULL, 'aesthetics_first_contact_v1_de', 'de', 'MARKETING', '[{"type":"BODY","text":"Hallo {{1}}, vielen Dank fuer Ihre Kontaktaufnahme! Wir haben gesehen dass Sie sich fuer {{2}} interessieren. Unsere Fachberater werden sich in Kuerze bei Ihnen melden. Bei Fragen koennen Sie uns gerne hier schreiben."}]', 'draft', true, 'aesthetics', 'first_contact'), (NULL, 'general_first_contact_v1_de', 'de', 'MARKETING', '[{"type":"BODY","text":"Hallo {{1}}, vielen Dank dass Sie unser Formular ausgefuellt haben! Wir haben gesehen dass Sie sich fuer {{2}} interessieren. Unser Team wird sich in Kuerze bei Ihnen melden. Bei Fragen koennen Sie uns gerne hier schreiben."}]', 'draft', true, 'general', 'first_contact') ON CONFLICT DO NOTHING;